INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("アヤネ", "2020/07/31 12:00:00", 10046, 0.0, 102301, "2030/12/17 14:59:59", 24, 401, 2, 0.0, 24001, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("アヤネ", "2020/07/31 12:00:00", 10046, 0.0, 102301, "2030/12/17 14:59:59", 24, 402, 1, 2.21, 24002, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("アヤネ", "2020/07/31 12:00:00", 10046, 0.0, 102301, "2030/12/17 14:59:59", 24, 403, 2, 0.0, 24003, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("アサヒ", "2020/07/31 12:00:00", 10046, 0.0, 192201, "2030/12/17 14:59:59", 24, 701, 2, 1.99, 24004, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("アサヒ", "2020/07/31 12:00:00", 10046, 0.0, 192201, "2030/12/17 14:59:59", 24, 702, 1, 2.21, 24005, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("アサヒ", "2020/07/31 12:00:00", 10046, 0.0, 192201, "2030/12/17 14:59:59", 24, 703, 2, 3.33, 24006, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("部員３", "2020/07/31 12:00:00", 10046, 0.0, 192301, "2030/12/17 14:59:59", 24, 801, 2, 0.0, 24007, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("部員３", "2020/07/31 12:00:00", 10046, 0.0, 192301, "2030/12/17 14:59:59", 24, 802, 1, 2.68, 24008, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("部員３", "2020/07/31 12:00:00", 10046, 0.0, 192301, "2030/12/17 14:59:59", 24, 803, 2, 0.0, 24009, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("", "2020/07/31 12:00:00", 10046, 0.0, 192501, "2030/12/17 14:59:59", 24, 501, 1, 0.0, 24010, "やった！", 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("", "2020/07/31 12:00:00", 10046, 0.0, 192501, "2030/12/17 14:59:59", 24, 502, 1, 0.0, 24011, "勝ったよ！", 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("", "2020/07/31 12:00:00", 10046, 0.0, 192501, "2030/12/17 14:59:59", 24, 503, 1, 0.0, 24012, "いい調子！", 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ミサト", "2020/07/31 12:00:00", 10046, 0.0, 113501, "2030/12/17 14:59:59", 24, 111, 6, 5.33, 24013, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ミサト", "2020/07/31 12:00:00", 10046, 0.0, 113501, "2030/12/17 14:59:59", 24, 112, 1, 6.85, 24014, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ミサト", "2020/07/31 12:00:00", 10046, 0.0, 113501, "2030/12/17 14:59:59", 24, 113, 1, 3.0, 24015, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ダイチ", "2020/07/31 12:00:00", 10046, 0.0, 192401, "2030/12/17 14:59:59", 24, 611, 1, 6.11, 24016, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ダイチ", "2020/07/31 12:00:00", 10046, 0.0, 192401, "2030/12/17 14:59:59", 24, 612, 1, 6.75, 24017, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ダイチ", "2020/07/31 12:00:00", 10046, 0.0, 192401, "2030/12/17 14:59:59", 24, 613, 2, 0.0, 24018, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ハツネ", "2020/07/31 12:00:00", 10046, 0.0, 113401, "2030/12/17 14:59:59", 24, 211, 2, 4.52, 24019, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ハツネ", "2020/07/31 12:00:00", 10046, 0.0, 113401, "2030/12/17 14:59:59", 24, 212, 2, 3.89, 24020, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ハツネ", "2020/07/31 12:00:00", 10046, 0.0, 113401, "2030/12/17 14:59:59", 24, 213, 1, 13.49, 24021, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("カヤ", "2020/07/31 12:00:00", 10046, 0.0, 106501, "2030/12/17 14:59:59", 24, 311, 1, 3.17, 24022, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("カヤ", "2020/07/31 12:00:00", 10046, 0.0, 106501, "2030/12/17 14:59:59", 24, 312, 1, 4.42, 24023, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("カヤ", "2020/07/31 12:00:00", 10046, 0.0, 106501, "2030/12/17 14:59:59", 24, 313, 6, 2.89, 24024, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("アヤネ", "2020/07/31 12:00:00", 10046, 0.0, 102301, "2030/12/17 14:59:59", 24, 421, 4, 3.71, 24025, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 3, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("アサヒ", "2020/07/31 12:00:00", 10046, 0.0, 192201, "2030/12/17 14:59:59", 24, 721, 2, 5.1, 24026, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("部員３", "2020/07/31 12:00:00", 10046, 0.0, 192301, "2030/12/17 14:59:59", 24, 821, 1, 4.34, 24027, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 3, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("", "2020/07/31 12:00:00", 10046, 0.0, 192501, "2030/12/17 14:59:59", 24, 521, 1, 0.0, 24028, "いい勝負だったよ\nまたやろうね", 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ミサト", "2020/07/31 12:00:00", 10046, -360.0, 113501, "2030/12/17 14:59:59", 24, 101, 1, 5.62, 24029, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ミサト", "2020/07/31 12:00:00", 10046, -360.0, 113501, "2030/12/17 14:59:59", 24, 102, 1, 9.58, 24030, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ミサト", "2020/07/31 12:00:00", 10046, -360.0, 113501, "2030/12/17 14:59:59", 24, 103, 2, 0.0, 24031, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 2, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ミサト", "2020/07/31 12:00:00", 10046, -360.0, 113501, "2030/12/17 14:59:59", 24, 104, 2, 9.13, 24032, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 1, 0.0);
INSERT INTO `v1_34e5ef79620998cc3cd9e6e34a931f25c416af083789a2013f5c00b2455792df` VALUES ("ミサト", "2020/07/31 12:00:00", 10046, -360.0, 113501, "2030/12/17 14:59:59", 24, 105, 1, 8.27, 24033, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 2, 0.0);
